const response = $.steps.scrapeWebsite.response || {};
const data = response.data || response;
const markdown = (data.markdown || data.content || data.text || '').slice(0, 10000);
const title = data.title || data.metadata?.title || '';
const description = data.metadata?.description || '';
const url = $.input.websiteUrl;

return { markdown: markdown, title: title, description: description, url: url, focusKeywords: $.input.focusKeywords || '' };

const data = $.steps.extractContent.output;

let prompt = 'You are an SEO analyst and search console expert. Analyze the following website content and provide a comprehensive SEO performance report.

';
prompt += 'WEBSITE: ' + data.url + '
';
prompt += 'TITLE: ' + data.title + '
';
prompt += 'META DESCRIPTION: ' + data.description + '
';
if (data.focusKeywords) prompt += 'TARGET KEYWORDS: ' + data.focusKeywords + '
';
prompt += '
CONTENT:
' + data.markdown + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Analyze page structure (H1, H2, H3 usage)
';
prompt += '- Evaluate title tag and meta description effectiveness
';
prompt += '- Identify target keywords and their density
';
prompt += '- Assess content quality and relevance
';
prompt += '- Provide estimated search rankings for key terms
';
prompt += '- List actionable improvements

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "domain": "",
';
prompt += '  "seoScore": 0,
';
prompt += '  "titleAnalysis": { "title": "", "length": 0, "isOptimal": true, "suggestion": "" },
';
prompt += '  "metaDescription": { "description": "", "length": 0, "isOptimal": true, "suggestion": "" },
';
prompt += '  "headingStructure": { "h1Count": 0, "h2Count": 0, "h3Count": 0, "isProper": true, "issues": [] },
';
prompt += '  "keywords": [{ "keyword": "", "density": "", "position": "title|h1|h2|body", "estimatedRanking": "" }],
';
prompt += '  "contentQuality": { "wordCount": 0, "readability": "high|medium|low", "uniqueness": "high|medium|low" },
';
prompt += '  "recommendations": [{ "priority": "high|medium|low", "area": "", "action": "", "impact": "" }],
';
prompt += '  "summary": "2-3 sentence SEO summary"
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { domain: $.input.websiteUrl, seoScore: 0, titleAnalysis: {}, metaDescription: {}, headingStructure: {}, keywords: [], contentQuality: {}, recommendations: [], summary: raw.slice(0, 300) }; }

const ai = $.steps.parseAI.output;

const overviewRows = [[
  ai.domain || '',
  String(ai.seoScore || 0),
  ai.titleAnalysis?.title || '',
  String(ai.titleAnalysis?.length || 0),
  ai.metaDescription?.description || '',
  String(ai.contentQuality?.wordCount || 0),
  ai.contentQuality?.readability || '',
  ai.summary || ''
]];

const keywordRows = [];
(ai.keywords || []).forEach(function(k) {
  keywordRows.push([k.keyword || '', k.density || '', k.position || '', k.estimatedRanking || '']);
});

const recRows = [];
(ai.recommendations || []).forEach(function(r) {
  recRows.push([r.priority || '', r.area || '', r.action || '', r.impact || '']);
});

return { overviewRows: overviewRows, keywordRows: keywordRows, recRows: recRows };

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'SEO Analysis Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Domain:* <' + (ai.domain || $.input.websiteUrl) + '|' + (ai.domain || $.input.websiteUrl) + '>' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*SEO Score:*\n' + (ai.seoScore || 'N/A') + '/100' },
  { type: 'mrkdwn', text: '*Readability:*\n' + (ai.contentQuality?.readability || 'N/A') }
] });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + (ai.summary || '').slice(0, 1500) } });

const recs = ai.recommendations || [];
if (recs.length > 0) {
  let recText = '*Top Recommendations:*\n';
  recs.slice(0, 5).forEach(function(r, i) {
    let icon = ':white_circle:';
    if (r.priority === 'high') icon = ':red_circle:';
    else if (r.priority === 'medium') icon = ':large_yellow_circle:';
    recText += icon + ' ' + (r.action || '') + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recText.slice(0, 1800) } });
}

const keywords = ai.keywords || [];
if (keywords.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Top Keywords:* ' + keywords.slice(0, 5).map(function(k) { return k.keyword; }).join(', ') } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Full report in Google Sheets | Powered by Firecrawl + Claude AI' }] });
const fallbackText = 'SEO Report for ' + (ai.domain || $.input.websiteUrl) + ': Score ' + (ai.seoScore || '?') + '/100';
return { blocks, fallbackText };
